/**
 * UI Slice
 *
 * State management for global UI state: toasts, modals, loading, errors.
 *
 * @see specs/006-user-interface.md Section 6.8
 */

import { createSlice } from '@belt/tools';
import type { Toast, ModalState, LoadingState, ErrorState, OptimizerJob } from '../types';

// =============================================================================
// UI Slice State
// =============================================================================

export interface UiSliceState {
  // Toast notifications
  toasts: Toast[];
  maxToasts: number;

  // Modal state
  modal: ModalState;

  // Loading indicators
  loading: LoadingState;

  // Global error state
  error: ErrorState;

  // Sidebar collapsed
  sidebarCollapsed: boolean;

  // Help panel open
  helpPanelOpen: boolean;

  // Keyboard shortcuts dialog visible
  keyboardShortcutsDialogOpen: boolean;

  // Keyboard shortcuts enabled
  shortcutsEnabled: boolean;

  // Theme
  theme: 'light' | 'dark' | 'system';

  // Optimizer jobs tracking
  optimizerJobs: OptimizerJob[];
  activeJobId: string | null;

  // Connection status
  isOnline: boolean;
  websocketConnected: boolean;

  // Sync status
  lastSyncAt: number | null;
  syncInProgress: boolean;

  // Index signature for MachineState compatibility
  [key: string]: unknown;
}

const initialUiState: UiSliceState = {
  toasts: [],
  maxToasts: 5,
  modal: {
    isOpen: false,
    type: null,
    data: null,
  },
  loading: {
    trains: false,
    pmSchedule: false,
    canvas: false,
    optimizer: false,
  },
  error: {
    message: null,
    code: null,
    details: null,
    timestamp: null,
  },
  sidebarCollapsed: false,
  helpPanelOpen: false,
  keyboardShortcutsDialogOpen: false,
  shortcutsEnabled: true,
  theme: 'system',
  optimizerJobs: [],
  activeJobId: null,
  isOnline: true,
  websocketConnected: false,
  lastSyncAt: null,
  syncInProgress: false,
};

let toastIdCounter = 0;

export const uiSlice = createSlice({
  id: 'ui',
  initial: initialUiState,
  cache: { policy: 'session' },
  reducers: {
    // ==========================================================================
    // Toast Notifications
    // ==========================================================================

    addToast: (
      s,
      toast: Omit<Toast, 'id' | 'createdAt'> & { id?: string }
    ) => {
      const state = s as UiSliceState;
      const newToast: Toast = {
        id: toast.id ?? `toast-${++toastIdCounter}`,
        type: toast.type,
        title: toast.title,
        message: toast.message,
        duration: toast.duration ?? 5000,
        dismissible: toast.dismissible ?? true,
        createdAt: Date.now(),
      };

      state.toasts.push(newToast);

      // Trim to max toasts
      if (state.toasts.length > state.maxToasts) {
        state.toasts.shift();
      }
    },

    removeToast: (s, toastId: string) => {
      const state = s as UiSliceState;
      state.toasts = state.toasts.filter((t) => t.id !== toastId);
    },

    clearToasts: (s) => {
      const state = s as UiSliceState;
      state.toasts = [];
    },

    // Convenience toast creators
    showSuccess: (s, payload: { title: string; message: string }) => {
      const state = s as UiSliceState;
      state.toasts.push({
        id: `toast-${++toastIdCounter}`,
        type: 'success',
        title: payload.title,
        message: payload.message,
        duration: 3000,
        dismissible: true,
        createdAt: Date.now(),
      });
    },

    showError: (s, payload: { title: string; message: string }) => {
      const state = s as UiSliceState;
      state.toasts.push({
        id: `toast-${++toastIdCounter}`,
        type: 'error',
        title: payload.title,
        message: payload.message,
        duration: 8000,
        dismissible: true,
        createdAt: Date.now(),
      });
    },

    showWarning: (s, payload: { title: string; message: string }) => {
      const state = s as UiSliceState;
      state.toasts.push({
        id: `toast-${++toastIdCounter}`,
        type: 'warning',
        title: payload.title,
        message: payload.message,
        duration: 6000,
        dismissible: true,
        createdAt: Date.now(),
      });
    },

    showInfo: (s, payload: { title: string; message: string }) => {
      const state = s as UiSliceState;
      state.toasts.push({
        id: `toast-${++toastIdCounter}`,
        type: 'info',
        title: payload.title,
        message: payload.message,
        duration: 5000,
        dismissible: true,
        createdAt: Date.now(),
      });
    },

    // ==========================================================================
    // Modal
    // ==========================================================================

    openModal: (s, payload: { type: string; data?: Record<string, unknown> }) => {
      const state = s as UiSliceState;
      state.modal = {
        isOpen: true,
        type: payload.type,
        data: payload.data ?? null,
      };
    },

    closeModal: (s) => {
      const state = s as UiSliceState;
      state.modal = {
        isOpen: false,
        type: null,
        data: null,
      };
    },

    updateModalData: (s, data: Record<string, unknown>) => {
      const state = s as UiSliceState;
      if (state.modal.isOpen) {
        state.modal.data = { ...state.modal.data, ...data };
      }
    },

    // ==========================================================================
    // Loading
    // ==========================================================================

    setLoading: (s, payload: Partial<LoadingState>) => {
      const state = s as UiSliceState;
      state.loading = { ...state.loading, ...payload };
    },

    startLoading: (s, key: keyof LoadingState) => {
      const state = s as UiSliceState;
      state.loading[key] = true;
    },

    stopLoading: (s, key: keyof LoadingState) => {
      const state = s as UiSliceState;
      state.loading[key] = false;
    },

    clearLoading: (s) => {
      const state = s as UiSliceState;
      state.loading = {
        trains: false,
        pmSchedule: false,
        canvas: false,
        optimizer: false,
      };
    },

    // ==========================================================================
    // Error
    // ==========================================================================

    setError: (
      s,
      payload: { message: string; code?: string; details?: Record<string, unknown> }
    ) => {
      const state = s as UiSliceState;
      state.error = {
        message: payload.message,
        code: payload.code ?? null,
        details: payload.details ?? null,
        timestamp: Date.now(),
      };
    },

    clearError: (s) => {
      const state = s as UiSliceState;
      state.error = {
        message: null,
        code: null,
        details: null,
        timestamp: null,
      };
    },

    // ==========================================================================
    // Layout
    // ==========================================================================

    toggleSidebar: (s) => {
      const state = s as UiSliceState;
      state.sidebarCollapsed = !state.sidebarCollapsed;
    },

    setSidebarCollapsed: (s, collapsed: boolean) => {
      const state = s as UiSliceState;
      state.sidebarCollapsed = collapsed;
    },

    toggleHelpPanel: (s) => {
      const state = s as UiSliceState;
      state.helpPanelOpen = !state.helpPanelOpen;
    },

    setHelpPanelOpen: (s, open: boolean) => {
      const state = s as UiSliceState;
      state.helpPanelOpen = open;
    },

    toggleKeyboardShortcutsDialog: (s) => {
      const state = s as UiSliceState;
      state.keyboardShortcutsDialogOpen = !state.keyboardShortcutsDialogOpen;
    },

    showKeyboardShortcutsDialog: (s) => {
      const state = s as UiSliceState;
      state.keyboardShortcutsDialogOpen = true;
    },

    hideKeyboardShortcutsDialog: (s) => {
      const state = s as UiSliceState;
      state.keyboardShortcutsDialogOpen = false;
    },

    // ==========================================================================
    // Preferences
    // ==========================================================================

    setShortcutsEnabled: (s, enabled: boolean) => {
      const state = s as UiSliceState;
      state.shortcutsEnabled = enabled;
    },

    setTheme: (s, theme: 'light' | 'dark' | 'system') => {
      const state = s as UiSliceState;
      state.theme = theme;
    },

    // ==========================================================================
    // Optimizer Jobs
    // ==========================================================================

    addOptimizerJob: (s, job: OptimizerJob) => {
      const state = s as UiSliceState;
      state.optimizerJobs.push(job);
      state.activeJobId = job.id;
    },

    updateOptimizerJob: (s, job: Partial<OptimizerJob> & { id: string }) => {
      const state = s as UiSliceState;
      const index = state.optimizerJobs.findIndex((j) => j.id === job.id);
      if (index !== -1) {
        state.optimizerJobs[index] = { ...state.optimizerJobs[index], ...job };
      }
    },

    removeOptimizerJob: (s, jobId: string) => {
      const state = s as UiSliceState;
      state.optimizerJobs = state.optimizerJobs.filter((j) => j.id !== jobId);
      if (state.activeJobId === jobId) {
        state.activeJobId = state.optimizerJobs[0]?.id ?? null;
      }
    },

    setActiveJob: (s, jobId: string | null) => {
      const state = s as UiSliceState;
      state.activeJobId = jobId;
    },

    clearCompletedJobs: (s) => {
      const state = s as UiSliceState;
      state.optimizerJobs = state.optimizerJobs.filter(
        (j) => j.status !== 'COMPLETED' && j.status !== 'FAILED'
      );
    },

    // ==========================================================================
    // Connection Status
    // ==========================================================================

    setOnlineStatus: (s, isOnline: boolean) => {
      const state = s as UiSliceState;
      state.isOnline = isOnline;
    },

    setWebsocketConnected: (s, connected: boolean) => {
      const state = s as UiSliceState;
      state.websocketConnected = connected;
    },

    // ==========================================================================
    // Sync Status
    // ==========================================================================

    startSync: (s) => {
      const state = s as UiSliceState;
      state.syncInProgress = true;
    },

    finishSync: (s) => {
      const state = s as UiSliceState;
      state.syncInProgress = false;
      state.lastSyncAt = Date.now();
    },

    // ==========================================================================
    // Reset
    // ==========================================================================

    reset: (s) => {
      const state = s as UiSliceState;
      Object.assign(state, initialUiState);
    },
  },
});

// =============================================================================
// Selectors
// =============================================================================

/** Check if any loading is in progress */
export function isAnyLoading(state: UiSliceState): boolean {
  return Object.values(state.loading).some(Boolean);
}

/** Get active optimizer job */
export function selectActiveJob(state: UiSliceState): OptimizerJob | undefined {
  return state.activeJobId
    ? state.optimizerJobs.find((j) => j.id === state.activeJobId)
    : undefined;
}

/** Get running optimizer jobs */
export function selectRunningJobs(state: UiSliceState): OptimizerJob[] {
  return state.optimizerJobs.filter((j) => j.status === 'RUNNING' || j.status === 'PENDING');
}

/** Check if there's an error */
export function hasError(state: UiSliceState): boolean {
  return state.error.message !== null;
}

/** Get visible toasts */
export function selectVisibleToasts(state: UiSliceState): Toast[] {
  const now = Date.now();
  return state.toasts.filter((t) => now - t.createdAt < t.duration);
}

/** Check connection status */
export function isFullyConnected(state: UiSliceState): boolean {
  return state.isOnline && state.websocketConnected;
}

/**
 * Keyboard Shortcuts Dialog
 *
 * Displays the list of keyboard shortcuts available in the MMS canvas.
 * Triggered by pressing '?' or from the Help menu.
 *
 * @see specs/006-user-interface.md Section 6.9.2
 */

import { Dialog, Classes, HTMLTable, Tag, Intent } from '@blueprintjs/core';
import { useUi } from '../store';
import type { UiSliceState } from '../store/slices/ui';

/**
 * Keyboard shortcut definition
 */
interface ShortcutDefinition {
  key: string;
  description: string;
  category: 'navigation' | 'zoom' | 'selection' | 'editing' | 'general';
}

/**
 * All keyboard shortcuts per spec 006.9.2
 */
const KEYBOARD_SHORTCUTS: ShortcutDefinition[] = [
  // Navigation shortcuts
  { key: 'Arrow keys', description: 'Pan canvas', category: 'navigation' },
  { key: 'Home', description: 'Go to today', category: 'navigation' },
  { key: 't', description: 'Go to today', category: 'navigation' },
  { key: 'Tab', description: 'Navigate between panels', category: 'navigation' },
  { key: 'Shift+Tab', description: 'Navigate between panels (reverse)', category: 'navigation' },

  // Zoom shortcuts
  { key: '+', description: 'Zoom in', category: 'zoom' },
  { key: '-', description: 'Zoom out', category: 'zoom' },
  { key: '1', description: 'Strategic view (12-year)', category: 'zoom' },
  { key: '2', description: 'Tactical-wide view (1-year)', category: 'zoom' },
  { key: '3', description: 'Tactical view (12-week)', category: 'zoom' },
  { key: '4', description: 'Operational view (4-week)', category: 'zoom' },
  { key: '5', description: 'Detail view (1-week)', category: 'zoom' },
  { key: 's', description: 'Strategic view', category: 'zoom' },
  { key: 'o', description: 'Operational view', category: 'zoom' },

  // Selection shortcuts
  { key: 'Enter', description: 'Activate selected element', category: 'selection' },
  { key: 'Space', description: 'Toggle selection', category: 'selection' },
  { key: 'Escape', description: 'Cancel drag / Close dialog / Deselect', category: 'selection' },

  // Editing shortcuts
  { key: 'l', description: 'Lock/unlock selected PM', category: 'editing' },
  { key: 'Delete', description: 'Cancel selected PM (with confirmation)', category: 'editing' },

  // General shortcuts
  { key: '?', description: 'Show keyboard shortcuts (this dialog)', category: 'general' },
];

/**
 * Category labels and order
 */
const CATEGORIES: { id: ShortcutDefinition['category']; label: string }[] = [
  { id: 'navigation', label: 'Navigation' },
  { id: 'zoom', label: 'Zoom & Views' },
  { id: 'selection', label: 'Selection' },
  { id: 'editing', label: 'Editing' },
  { id: 'general', label: 'General' },
];

/**
 * Shortcut key badge component
 */
function KeyBadge({ keyName }: { keyName: string }) {
  const parts = keyName.split('+');
  return (
    <span style={{ display: 'inline-flex', gap: '4px', alignItems: 'center' }}>
      {parts.map((part, index) => (
        <span key={index}>
          <Tag minimal style={{ fontFamily: 'monospace', fontWeight: 600, fontSize: '12px' }}>
            {part.trim()}
          </Tag>
          {index < parts.length - 1 && <span style={{ margin: '0 2px', color: '#5c7080' }}>+</span>}
        </span>
      ))}
    </span>
  );
}

/**
 * Shortcuts table for a category
 */
function ShortcutCategory({
  category,
  shortcuts,
}: {
  category: { id: string; label: string };
  shortcuts: ShortcutDefinition[];
}) {
  return (
    <div style={{ marginBottom: '20px' }}>
      <h4 style={{ margin: '0 0 8px 0', color: '#5c7080', fontSize: '13px', fontWeight: 600 }}>
        {category.label}
      </h4>
      <HTMLTable
        compact
        striped
        style={{ width: '100%', fontSize: '13px' }}
      >
        <tbody>
          {shortcuts.map((shortcut) => (
            <tr key={shortcut.key}>
              <td style={{ width: '140px', paddingRight: '16px' }}>
                <KeyBadge keyName={shortcut.key} />
              </td>
              <td>{shortcut.description}</td>
            </tr>
          ))}
        </tbody>
      </HTMLTable>
    </div>
  );
}

/**
 * Keyboard Shortcuts Dialog Component
 *
 * Displays all available keyboard shortcuts organized by category.
 * Uses @belt/tools state management for dialog visibility.
 */
export function KeyboardShortcutsDialog() {
  const { state: uiStateRaw, actions: uiActions } = useUi();
  const uiState = uiStateRaw as unknown as UiSliceState;

  const handleClose = () => {
    uiActions.hideKeyboardShortcutsDialog();
  };

  // Group shortcuts by category
  const shortcutsByCategory = CATEGORIES.map((category) => ({
    category,
    shortcuts: KEYBOARD_SHORTCUTS.filter((s) => s.category === category.id),
  })).filter(({ shortcuts }) => shortcuts.length > 0);

  return (
    <Dialog
      isOpen={uiState.keyboardShortcutsDialogOpen}
      onClose={handleClose}
      title="Keyboard Shortcuts"
      icon="key-command"
      style={{ width: '520px' }}
    >
      <div className={Classes.DIALOG_BODY} style={{ maxHeight: '60vh', overflowY: 'auto' }}>
        <p style={{ marginTop: 0, marginBottom: '20px', color: '#5c7080', fontSize: '13px' }}>
          These keyboard shortcuts help you navigate and interact with the PM schedule canvas efficiently.
        </p>

        {shortcutsByCategory.map(({ category, shortcuts }) => (
          <ShortcutCategory
            key={category.id}
            category={category}
            shortcuts={shortcuts}
          />
        ))}

        <div style={{ marginTop: '16px', padding: '12px', backgroundColor: '#f5f8fa', borderRadius: '4px' }}>
          <Tag intent={Intent.PRIMARY} minimal style={{ marginRight: '8px' }}>
            Tip
          </Tag>
          <span style={{ fontSize: '12px', color: '#5c7080' }}>
            Press <KeyBadge keyName="Escape" /> to close this dialog or any modal.
            Shortcuts are disabled when typing in input fields.
          </span>
        </div>
      </div>

      <div className={Classes.DIALOG_FOOTER}>
        <div className={Classes.DIALOG_FOOTER_ACTIONS}>
          <Tag minimal style={{ marginRight: 'auto', color: '#5c7080' }}>
            {uiState.shortcutsEnabled ? 'Shortcuts enabled' : 'Shortcuts disabled'}
          </Tag>
        </div>
      </div>
    </Dialog>
  );
}

