   532→
   533→/** Constraint warning for detail view */
   534→export interface DetailConstraintWarning {
   535→  type: string;
   536→  message: string;
   537→}
   538→
   539→/** Crew assignment for PM */
   540→export interface CrewAssignment {
   541→  crewId: string;
   542→  crewName: string;
   543→  role: string;
