   595→  detailExpandedPmIds: string[];
   596→  [key: string]: unknown;
   597→}
   598→
   599→function getDefaultTacticalDates(): { from: string; to: string } {
   600→  const today = new Date();
   601→  const fromDate = new Date(today);
   602→  fromDate.setDate(today.getDate() - today.getDay()); // Start of current week
   603→  const toDate = new Date(fromDate);
   604→  toDate.setDate(toDate.getDate() + 12 * 7); // 12 weeks ahead
   605→  return {
   606→    from: fromDate.toISOString().split('T')[0],
   607→    to: toDate.toISOString().split('T')[0],
   608→  };
   609→}
   610→
   611→function getDefaultTacticalWideDates(): { from: string; to: string } {
   612→  const today = new Date();
   613→  const fromDate = new Date(today.getFullYear(), today.getMonth(), 1); // Start of current month
   614→  const toDate = new Date(fromDate);
   615→  toDate.setMonth(toDate.getMonth() + 12); // 12 months ahead
   616→  return {
   617→    from: fromDate.toISOString().split('T')[0],
   618→    to: toDate.toISOString().split('T')[0],
   619→  };
   620→}
   621→
   622→function getDefaultOperationalDates(): { from: string; to: string } {
   623→  const today = new Date();
   624→  const fromDate = new Date(today);
   625→  fromDate.setDate(today.getDate() - today.getDay()); // Start of current week
   626→  const toDate = new Date(fromDate);
   627→  toDate.setDate(toDate.getDate() + 4 * 7); // 4 weeks ahead
   628→  return {
   629→    from: fromDate.toISOString().split('T')[0],
   630→    to: toDate.toISOString().split('T')[0],
   631→  };
   632→}
