/**
 * Load tactical-wide canvas data from API
 *
 * Fetches PM schedule data aggregated at monthly granularity for the
 * TACTICAL_WIDE zoom level (4-8). Shows compressed PM blocks for 1-year view.
 */
export async function loadTacticalWideData(
  dispatch: {
    setTacticalWideLoading: (loading: boolean) => void;
    setTacticalWideData: (data: TacticalWideCanvasData) => void;
    setTacticalWideError: (error: string) => void;
  },
  options: { baseUrl?: string; fromDate?: string; toDate?: string; trainIds?: string[] } = {}
): Promise<void> {
  const {
    baseUrl = '/api/v1',
    fromDate,
    toDate,
    trainIds,
  } = options;

  dispatch.setTacticalWideLoading(true);

  const params = new URLSearchParams();
  if (fromDate) {
    params.set('fromDate', fromDate);
  }
  if (toDate) {
    params.set('toDate', toDate);
  }
  if (trainIds && trainIds.length > 0) {
    params.set('trainIds', trainIds.join(','));
  }

  try {
    // Tactical-wide uses the tactical endpoint with monthly aggregation
    // The API returns the same data format but filtered for the date range
    const response = await fetch(`${baseUrl}/canvas/tactical-wide?${params}`);

    if (!response.ok) {
      throw new Error(`Failed to fetch tactical-wide data: ${response.status}`);
    }

    const json = (await response.json()) as { data: TacticalWideCanvasData };
    dispatch.setTacticalWideData(json.data);
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    dispatch.setTacticalWideError(message);
  }
}

