/**
 * MMS Infinite Canvas
 *
 * The main canvas component that renders PM schedule data at different zoom levels.
 * Uses deck.gl for strategic view (WebGL) and Konva for tactical/operational views (Canvas 2D).
 *
 * Zoom Level Rendering:
 * - STRATEGIC (0-4): deck.gl WebGL heatmap
 * - TACTICAL_WIDE (4-8): deck.gl WebGL compressed blocks
 * - TACTICAL (8-12): Konva HTML5 Canvas Gantt
 * - OPERATIONAL (12-16): Konva HTML5 Canvas detailed cards
 * - DETAIL (16+): React DOM overlay
 *
 * Based on specs/006-user-interface.md Section 6.3.
 */

import { useRef } from 'react';
import { Card, NonIdealState, Spinner, Tag, Button, ButtonGroup, OverlayToaster, Intent, Position } from '@blueprintjs/core';

import { useCanvas, useCanvasData, useFleet, usePm, useUi, useOverlay, loadStrategicData, loadTacticalData, loadTacticalWideData, loadOperationalData, loadDetailData, loadBaselineShadowData } from '../../store';
import type { CanvasSliceState } from '../../store/slices/canvas';
import type { CanvasDataState } from '../../store/slices/canvas';
import type { FleetSliceState } from '../../store/slices/fleet';
import type { PmSliceState } from '../../store/slices/pm';
import type { UiSliceState } from '../../store/slices/ui';
import type { OverlaySliceState } from '../../store/slices/overlay';
import type { ZoomLevel } from '../../store/types';
import { StrategicHeatmapLayer, TacticalWideLayer, TacticalGanttLayer, OperationalDetailLayer, DetailCardOverlay, type HeatmapCell, type PmBlock, type OperationalPmBlock, type DragValidationState, type PmMoveImpact } from './layers';
import { DragConfirmationDialog } from './DragConfirmationDialog';
import { quickValidatePmMove, createDebouncedValidation, getPmMoveImpact, commitPmMove, createCanvasKeyboardHandler, type KeyboardHandlerCallbacks } from './utils';
import { KeyboardShortcutsDialog } from '../KeyboardShortcutsDialog';

// Toaster helper for showing notifications
// Uses the static show method which handles async creation
async function showToast(options: {
  intent: typeof Intent[keyof typeof Intent];
  icon: 'error' | 'tick' | 'warning-sign' | 'info-sign';
  message: string;
  timeout: number;
}): Promise<void> {
  const toaster = await OverlayToaster.createAsync({ position: Position.TOP_RIGHT });
  toaster.show(options);
}

/** Default canvas dimensions when container size is not available */
const DEFAULT_CANVAS_WIDTH = 1200;
const DEFAULT_CANVAS_HEIGHT = 800;

// Drag confirmation state interface
interface DragConfirmState {
  isOpen: boolean;
  pmId: string | null;
  pmCode: string;
  trainNumber: string;
  sourceDate: string;
  targetDate: string;
  impact: PmMoveImpact | null;
  isLoadingImpact: boolean;
}

const initialDragConfirmState: DragConfirmState = {
  isOpen: false,
  pmId: null,
  pmCode: '',
  trainNumber: '',
  sourceDate: '',
  targetDate: '',
  impact: null,
  isLoadingImpact: false,
};

export function InfiniteCanvas() {
  const { state: canvasStateRaw, actions: canvasActions } = useCanvas();
  const { state: canvasDataStateRaw, actions: canvasDataActions } = useCanvasData();
  const { state: fleetStateRaw } = useFleet();
  const { state: pmStateRaw, actions: pmActions } = usePm();
  const { state: uiStateRaw, actions: uiActions } = useUi();
  const { state: overlayStateRaw, actions: overlayActions } = useOverlay();

  const canvasState = canvasStateRaw as unknown as CanvasSliceState;
  const canvasDataState = canvasDataStateRaw as unknown as CanvasDataState;
  const fleetState = fleetStateRaw as unknown as FleetSliceState;
  const pmState = pmStateRaw as unknown as PmSliceState;
  const uiState = uiStateRaw as unknown as UiSliceState;
  const overlayState = overlayStateRaw as unknown as OverlaySliceState;

  const { zoom, zoomLevel, viewport, isPanning, layers } = canvasState;
  const {
    strategicData, strategicLoading, strategicError, fromYear, toYear,
    tacticalWideData, tacticalWideLoading, tacticalWideError, tacticalWideFromDate, tacticalWideToDate,
    tacticalData, tacticalLoading, tacticalError, tacticalFromDate, tacticalToDate,
    operationalData, operationalLoading, operationalError, operationalFromDate, operationalToDate,
    detailData, detailLoading, detailError, detailFromDate, detailToDate, detailExpandedPmIds
  } = canvasDataState;
  const isLoading = fleetState.trains.length === 0;

  const tooltipPosRef = useRef<{ x: number; y: number }>({ x: 0, y: 0 });
  const tooltipRef = useRef<HTMLDivElement>(null);

  // Drag state refs
  const dragValidationRef = useRef<DragValidationState | null>(null);
  const draggingPmRef = useRef<{
    pmId: string;
    pmCode: string;
    trainId: string;
    trainNumber: string;
    sourceDate: string;
    constraintStart: string;
    constraintEnd: string;
    isLocked: boolean;
  } | null>(null);
  const dragConfirmRef = useRef<DragConfirmState>(initialDragConfirmState);

  // Create debounced API validation
  const debouncedValidationRef = useRef(
    createDebouncedValidation((result) => {
      dragValidationRef.current = result;
      if (draggingPmRef.current) {
        pmActions.setDragValidation({
          isValid: result.isValid,
          message: result.message,
          violations: result.violations,
        });
      }
    }, { delay: 150 })
  );

  // Ref for container to handle focus
  const containerRef = useRef<HTMLDivElement>(null);

  // ==========================================================================
  // Keyboard Handler Callbacks
  // ==========================================================================

  const keyboardCallbacksRef = useRef<KeyboardHandlerCallbacks>({
    // Navigation
    onPan: (direction, amount) => {
      const delta = { dx: 0, dy: 0 };
      switch (direction) {
        case 'up':
          delta.dy = -amount;
          break;
        case 'down':
          delta.dy = amount;
          break;
        case 'left':
          delta.dx = -amount;
          break;
        case 'right':
          delta.dx = amount;
          break;
      }
      canvasActions.pan(delta);
    },
    onGoToToday: () => {
      canvasActions.goToToday();
    },

    // Zoom
    onZoomIn: () => {
      canvasActions.zoomIn(1.2);
    },
    onZoomOut: () => {
      canvasActions.zoomOut(1.2);
    },
    onSetZoomLevel: (level: ZoomLevel) => {
      canvasActions.setZoomLevel(level);
    },

    // Selection
    onClearSelection: () => {
      canvasActions.clearSelection();
    },
    onToggleSelection: () => {
      // Toggle multi-select mode
      canvasActions.setMultiSelect(!canvasState.selection.isMultiSelect);
    },
    onActivateSelected: () => {
      // Activate selected PM - for now, zoom to tactical view showing the PM
      const selectedPmId = canvasState.selection.selectedPmIds[0];
      if (selectedPmId) {
        // Zoom to tactical view to see PM details
        canvasActions.setZoomLevel('TACTICAL');
      }
    },

    // Editing
    onToggleLock: () => {
      const selectedPmId = canvasState.selection.selectedPmIds[0];
      if (selectedPmId) {
        // In production, this would call the API to lock/unlock
        void showToast({
          intent: Intent.PRIMARY,
          icon: 'info-sign',
          message: 'Lock/unlock PM feature - API integration pending',
          timeout: 3000,
        });
      }
    },
    onDeleteSelected: () => {
      const selectedPmId = canvasState.selection.selectedPmIds[0];
      if (selectedPmId) {
        // In production, this would open a confirmation dialog
        uiActions.openModal({ type: 'confirm-delete-pm', data: { pmId: selectedPmId } });
      }
    },

    // Dialogs
    onShowKeyboardHelp: () => {
      uiActions.showKeyboardShortcutsDialog();
    },
    onCloseDialog: () => {
      // Close any open dialog
      if (uiState.keyboardShortcutsDialogOpen) {
        uiActions.hideKeyboardShortcutsDialog();
      } else if (uiState.modal.isOpen) {
        uiActions.closeModal();
      }
    },

    // State queries
    isShortcutsEnabled: () => uiState.shortcutsEnabled,
    hasOpenDialog: () => uiState.modal.isOpen || uiState.keyboardShortcutsDialogOpen || dragConfirmRef.current.isOpen,
    isDragging: () => pmState.drag.isDragging,
    getSelectedPmId: () => canvasState.selection.selectedPmIds[0] || null,
  });

  // Update ref values on each render (refs don't cause re-renders)
  keyboardCallbacksRef.current.isShortcutsEnabled = () => uiState.shortcutsEnabled;
  keyboardCallbacksRef.current.hasOpenDialog = () => uiState.modal.isOpen || uiState.keyboardShortcutsDialogOpen || dragConfirmRef.current.isOpen;
  keyboardCallbacksRef.current.isDragging = () => pmState.drag.isDragging;
  keyboardCallbacksRef.current.getSelectedPmId = () => canvasState.selection.selectedPmIds[0] || null;

  // Create keyboard handler
  const handleKeyDown = createCanvasKeyboardHandler(keyboardCallbacksRef.current);

  const handleWheel = (event: React.WheelEvent) => {
    event.preventDefault();
    const delta = event.deltaY > 0 ? -0.5 : 0.5;
    const newZoom = Math.max(0, Math.min(20, zoom + delta));
    canvasActions.setZoom(newZoom);
  };

  const handleMouseDown = (event: React.MouseEvent) => {
    if (event.button === 0) {
      canvasActions.startPanning();
    }
  };

  const handleMouseUp = () => {
    canvasActions.stopPanning();
  };

  const handleMouseMove = (event: React.MouseEvent) => {
    if (isPanning) {
      canvasActions.pan({
        dx: -event.movementX,
        dy: -event.movementY,
      });
    }
    tooltipPosRef.current = { x: event.clientX, y: event.clientY };
  };

  const handleLoadStrategicData = () => {
    loadStrategicData(canvasDataActions, {
      fromYear,
      toYear,
    });
  };

  const handleLoadTacticalWideData = () => {
    loadTacticalWideData(canvasDataActions, {
      fromDate: tacticalWideFromDate,
      toDate: tacticalWideToDate,
    });
  };

  const handleLoadTacticalData = () => {
    loadTacticalData(canvasDataActions, {
      fromWeek: tacticalFromDate,
      toWeek: tacticalToDate,
    });
  };

  const handleLoadOperationalData = () => {
    loadOperationalData(canvasDataActions, {
      fromDate: operationalFromDate,
      toDate: operationalToDate,
    });
  };

  const handleLoadDetailData = () => {
    loadDetailData(canvasDataActions, {
      fromDate: detailFromDate,
      toDate: detailToDate,
    });
  };

  const handleLoadBaselineShadowData = () => {
    loadBaselineShadowData(overlayActions, {
      fromDate: tacticalFromDate,
      toDate: tacticalToDate,
      baselineId: overlayState.baselineShadowBaselineId ?? undefined,
    });
  };

  const handleDetailPmSelect = (pmId: string) => {
    canvasActions.selectPm(pmId);
  };

  const handleDetailPmExpand = (pmId: string) => {
    canvasDataActions.expandDetailPm(pmId);
  };

  const handleDetailPmCollapse = (pmId: string) => {
    canvasDataActions.collapseDetailPm(pmId);
  };

  const handleDetailPmEdit = (pmId: string, field: string) => {
    // In production, this would dispatch an edit action to the PM service
    console.log(`Edit PM ${pmId} field ${field}`);
  };

  const handleDetailPmLock = (pmId: string) => {
    // In production, this would dispatch a lock action
    console.log(`Lock PM ${pmId}`);
  };

  const handleDetailPmUnlock = (pmId: string) => {
    // In production, this would dispatch an unlock action
    console.log(`Unlock PM ${pmId}`);
  };

  const handleDetailViewHistory = (pmId: string) => {
    // In production, this would open a history panel
    console.log(`View history for PM ${pmId}`);
  };

  // ==========================================================================
  // Drag-and-Drop Handlers
  // ==========================================================================

  const handlePmDragStart = (pmId: string, sourceDate: string) => {
    // Find PM in tactical data
    const pm = tacticalData?.pmBlocks.find(p => p.pmId === pmId);
    if (!pm) return;

    // Store drag info
    draggingPmRef.current = {
      pmId,
      pmCode: pm.pmCode,
      trainId: pm.trainId,
      trainNumber: pm.trainNumber,
      sourceDate,
      constraintStart: pm.constraintStart,
      constraintEnd: pm.constraintEnd,
      isLocked: pm.isLocked,
    };

    // Initialize drag state in PM slice
    pmActions.startDrag({ pmId, sourceDate });

    // Set initial validation (quick check)
    const quickResult = quickValidatePmMove({
      pmId,
      currentDate: sourceDate,
      targetDate: sourceDate,
      trainId: pm.trainId,
      constraintStart: pm.constraintStart,
      constraintEnd: pm.constraintEnd,
      isLocked: pm.isLocked,
    });
    dragValidationRef.current = quickResult;
    pmActions.setDragValidation({
      isValid: quickResult.isValid,
      message: quickResult.message,
      violations: quickResult.violations,
    });
  };

  const handlePmDragMove = (pmId: string, targetDate: string) => {
    const dragInfo = draggingPmRef.current;
    if (!dragInfo || dragInfo.pmId !== pmId) return;

    // Update target date in PM slice
    pmActions.updateDragTarget(targetDate);

    // Quick client-side validation
    const quickResult = quickValidatePmMove({
      pmId,
      currentDate: dragInfo.sourceDate,
      targetDate,
      trainId: dragInfo.trainId,
      constraintStart: dragInfo.constraintStart,
      constraintEnd: dragInfo.constraintEnd,
      isLocked: dragInfo.isLocked,
    });
    dragValidationRef.current = quickResult;
    pmActions.setDragValidation({
      isValid: quickResult.isValid,
      message: quickResult.message,
      violations: quickResult.violations,
    });

    // If quick validation passes, trigger debounced API validation
    if (quickResult.isValid && targetDate !== dragInfo.sourceDate) {
      debouncedValidationRef.current.validate({
        pmId,
        currentDate: dragInfo.sourceDate,
        targetDate,
        trainId: dragInfo.trainId,
      });
    }
  };

  const handlePmDragEnd = async (pmId: string, targetDate: string) => {
    const dragInfo = draggingPmRef.current;
    if (!dragInfo || dragInfo.pmId !== pmId) {
      // Clear drag state
      pmActions.cancelDrag();
      draggingPmRef.current = null;
      return;
    }

    // Cancel pending validation
    debouncedValidationRef.current.cancel();

    // If no change, just cancel
    if (targetDate === dragInfo.sourceDate) {
      pmActions.cancelDrag();
      draggingPmRef.current = null;
      return;
    }

    // Final quick validation
    const finalValidation = quickValidatePmMove({
      pmId,
      currentDate: dragInfo.sourceDate,
      targetDate,
      trainId: dragInfo.trainId,
      constraintStart: dragInfo.constraintStart,
      constraintEnd: dragInfo.constraintEnd,
      isLocked: dragInfo.isLocked,
    });

    // If invalid, snap back and show toast
    if (!finalValidation.isValid) {
      pmActions.cancelDrag();
      draggingPmRef.current = null;
      void showToast({
        intent: Intent.DANGER,
        icon: 'error',
        message: finalValidation.message || 'Cannot reschedule: constraint violation',
        timeout: 5000,
      });
      return;
    }

    // Open confirmation dialog
    dragConfirmRef.current = {
      isOpen: true,
      pmId,
      pmCode: dragInfo.pmCode,
      trainNumber: dragInfo.trainNumber,
      sourceDate: dragInfo.sourceDate,
      targetDate,
      impact: null,
      isLoadingImpact: true,
    };
    // Force re-render by ending drag with commit=false (optimistic update)
    pmActions.endDrag(false);

    // Load impact assessment
    try {
      const impact = await getPmMoveImpact({
        pmId,
        currentDate: dragInfo.sourceDate,
        targetDate,
        trainId: dragInfo.trainId,
      });
      dragConfirmRef.current = {
        ...dragConfirmRef.current,
        impact,
        isLoadingImpact: false,
      };
    } catch {
      dragConfirmRef.current = {
        ...dragConfirmRef.current,
        isLoadingImpact: false,
      };
    }

    // Keep draggingPmRef for the confirmation dialog
  };

  const handleDragConfirm = async () => {
    const confirmState = dragConfirmRef.current;
    const dragInfo = draggingPmRef.current;

    if (!confirmState.pmId || !dragInfo) {
      handleDragCancel();
      return;
    }

    try {
      // Commit the move to API
      await commitPmMove({
        pmId: confirmState.pmId,
        currentDate: confirmState.sourceDate,
        targetDate: confirmState.targetDate,
        trainId: dragInfo.trainId,
        reason: 'Manual reschedule via canvas drag-and-drop',
      });

      // Confirm move in PM slice (updates local state)
      pmActions.confirmMove(confirmState.pmId);

      // Show success toast
      void showToast({
        intent: Intent.SUCCESS,
        icon: 'tick',
        message: `${confirmState.pmCode} rescheduled to ${confirmState.targetDate}`,
        timeout: 3000,
      });

      // Reload tactical data to reflect changes
      handleLoadTacticalData();
    } catch (error) {
      // Reject move (revert to original date)
      pmActions.rejectMove(confirmState.pmId);

      // Show error toast
      void showToast({
        intent: Intent.DANGER,
        icon: 'error',
        message: error instanceof Error ? error.message : 'Failed to reschedule PM',
        timeout: 5000,
      });
    } finally {
      // Close dialog and clear state
      dragConfirmRef.current = initialDragConfirmState;
      draggingPmRef.current = null;
    }
  };

  const handleDragCancel = () => {
    const confirmState = dragConfirmRef.current;

    // Revert the move if pending
    if (confirmState.pmId) {
      pmActions.rejectMove(confirmState.pmId);
    }

    // Clear state
    dragConfirmRef.current = initialDragConfirmState;
    draggingPmRef.current = null;
  };

  const handlePmBlockHover = (pm: PmBlock | null) => {
    if (tooltipRef.current) {
      if (pm) {
        tooltipRef.current.style.display = 'block';
        tooltipRef.current.style.left = `${tooltipPosRef.current.x + 10}px`;
        tooltipRef.current.style.top = `${tooltipPosRef.current.y + 10}px`;
        tooltipRef.current.innerHTML = `
          <div style="font-weight: 600; margin-bottom: 4px;">
            ${pm.pmCode} - ${pm.trainNumber}
          </div>
          <div style="color: #64748b;">
            <div>Date: <strong>${pm.targetDate}</strong></div>
            <div>Duration: <strong>${pm.durationDays} day${pm.durationDays > 1 ? 's' : ''}</strong></div>
            <div>Status: <strong>${pm.status}</strong></div>
            ${pm.depotCode ? `<div>Depot: <strong>${pm.depotCode}</strong></div>` : ''}
            ${pm.trackNumber ? `<div>Track: <strong>${pm.trackNumber}</strong></div>` : ''}
            ${pm.estimatedHours ? `<div>Hours: <strong>${pm.estimatedHours}h</strong></div>` : ''}
            ${pm.isLocked ? '<div style="color: #d97706;">🔒 Locked</div>' : ''}
          </div>
        `;
      } else {
        tooltipRef.current.style.display = 'none';
      }
    }
  };

  const handlePmBlockClick = (pmId: string) => {
    canvasActions.selectPm(pmId);
  };

  // Tactical-Wide block handlers
  const handleTacticalWideBlockHover = (block: { pmId: string; trainNumber: string; pmCode: string; targetDate: string; status: string; durationWeeks: number; isLocked: boolean } | null) => {
    if (tooltipRef.current) {
      if (block) {
        tooltipRef.current.style.display = 'block';
        tooltipRef.current.style.left = `${tooltipPosRef.current.x + 10}px`;
        tooltipRef.current.style.top = `${tooltipPosRef.current.y + 10}px`;
        tooltipRef.current.innerHTML = `
          <div style="font-weight: 600; margin-bottom: 4px;">
            ${block.pmCode} - ${block.trainNumber}
          </div>
          <div style="color: #64748b;">
            <div>Date: <strong>${block.targetDate}</strong></div>
            <div>Status: <strong>${block.status}</strong></div>
            <div>Duration: <strong>~${block.durationWeeks} week(s)</strong></div>
            ${block.isLocked ? '<div style="color: #d97706;">🔒 Locked</div>' : ''}
          </div>
        `;
      } else {
        tooltipRef.current.style.display = 'none';
      }
    }
  };

  const handleTacticalWideBlockClick = (block: { pmId: string }) => {
    canvasActions.selectPm(block.pmId);
  };

  const handleMonthClick = (month: number, year: number) => {
    // Zoom into tactical view for the clicked month
    canvasActions.setZoom(10); // Move to TACTICAL zoom level
    const startDate = new Date(year, month, 1);
    const endDate = new Date(year, month + 3, 0); // 3 months view
    canvasActions.setViewport({
      startDate: startDate.toISOString().split('T')[0],
      endDate: endDate.toISOString().split('T')[0],
    });
  };

  const handleCellHover = (cell: HeatmapCell | null) => {
    if (tooltipRef.current) {
      if (cell) {
        tooltipRef.current.style.display = 'block';
        tooltipRef.current.style.left = `${tooltipPosRef.current.x + 10}px`;
        tooltipRef.current.style.top = `${tooltipPosRef.current.y + 10}px`;
        tooltipRef.current.innerHTML = `
          <div style="font-weight: 600; margin-bottom: 4px;">
            Train ${cell.trainNumber} - ${cell.year}
          </div>
          <div style="color: #64748b;">
            <div>PM Count: <strong>${cell.pmCount}</strong></div>
            <div>Total Hours: <strong>${cell.totalHours.toFixed(1)}h</strong></div>
            ${cell.completedCount > 0 ? `<div>Completed: <strong>${cell.completedCount}</strong></div>` : ''}
            ${cell.lockedCount > 0 ? `<div>Locked: <strong>${cell.lockedCount}</strong></div>` : ''}
          </div>
        `;
      } else {
        tooltipRef.current.style.display = 'none';
      }
    }
  };

  const handleCellClick = (cell: HeatmapCell) => {
    canvasActions.setZoom(6);
    canvasActions.setViewport({
      startDate: `${cell.year}-01-01`,
      endDate: `${cell.year}-12-31`,
      trainIds: [cell.trainId],
    });
  };

  const handleYearClick = (year: number) => {
    canvasActions.setZoom(6);
    canvasActions.setViewport({
      startDate: `${year}-01-01`,
      endDate: `${year}-12-31`,
    });
  };

  const handleOperationalPmHover = (pm: OperationalPmBlock | null) => {
    if (tooltipRef.current) {
      if (pm) {
        tooltipRef.current.style.display = 'block';
        tooltipRef.current.style.left = `${tooltipPosRef.current.x + 10}px`;
        tooltipRef.current.style.top = `${tooltipPosRef.current.y + 10}px`;
        const materialInfo = pm.materials.length > 0
          ? pm.materials.map(m => `${m.status === 'AVAILABLE' ? '✓' : '⚠'} ${m.materialName}`).slice(0, 3).join('<br/>')
          : '<span style="color: #94a3b8; font-style: italic;">No materials required</span>';
        tooltipRef.current.innerHTML = `
          <div style="font-weight: 600; margin-bottom: 8px;">
            ${pm.pmCode} - ${pm.trainNumber}
          </div>
          <div style="color: #64748b;">
            <div><strong>${pm.pmDescription}</strong></div>
            <div style="margin-top: 4px;">Date: <strong>${pm.targetDate} - ${pm.endDate}</strong></div>
            <div>Duration: <strong>${pm.durationDays} day${pm.durationDays > 1 ? 's' : ''}</strong></div>
            <div>Status: <strong>${pm.status}</strong></div>
            ${pm.depotCode ? `<div>Depot: <strong>${pm.depotCode}</strong></div>` : ''}
            ${pm.trackNumber ? `<div>Track: <strong>${pm.trackNumber}</strong></div>` : ''}
            ${pm.estimatedHours ? `<div>Hours: <strong>${pm.estimatedHours}h</strong></div>` : ''}
            ${pm.assignedShift ? `<div>Shift: <strong>${pm.assignedShift}</strong></div>` : ''}
            ${pm.isLocked ? '<div style="color: #d97706; margin-top: 4px;">🔒 Locked in Maximo</div>' : ''}
            <div style="margin-top: 8px; border-top: 1px solid #e2e8f0; padding-top: 8px;">
              <strong>Materials:</strong><br/>
              ${materialInfo}
            </div>
          </div>
        `;
      } else {
        tooltipRef.current.style.display = 'none';
      }
    }
  };

  const renderContent = () => {
    if (isLoading) {
      return (
        <NonIdealState
          icon={<Spinner size={48} />}
          title="Loading fleet data..."
          description="Fetching trains and PM schedule"
        />
      );
    }

    if (fleetState.trains.length === 0) {
      return (
        <NonIdealState
          icon="train"
          title="No trains found"
          description="No trains match the current filters"
        />
      );
    }

    if (zoomLevel === 'STRATEGIC') {
      if (strategicLoading) {
        return (
          <NonIdealState
            icon={<Spinner size={48} />}
            title="Loading strategic view..."
            description="Fetching PM density data"
          />
        );
      }

      if (strategicError) {
        return (
          <NonIdealState
            icon="error"
            title="Error loading strategic view"
            description={strategicError}
            action={
              <Button intent="primary" onClick={handleLoadStrategicData}>
                Retry
              </Button>
            }
          />
        );
      }

      if (!strategicData) {
        return (
          <NonIdealState
            icon="heat-grid"
            title="Strategic View"
            description="Load PM density heatmap for multi-year planning"
            action={
              <ButtonGroup>
                <Button intent="primary" onClick={handleLoadStrategicData}>
                  Load Strategic Data
                </Button>
              </ButtonGroup>
            }
          >
            <div style={{ marginTop: '16px', fontSize: '12px', color: 'var(--pt-text-muted)' }}>
