/**
 * Keyboard Handler Tests
 *
 * Tests for canvas keyboard shortcuts implementation.
 * Based on spec 006.9.2 keyboard shortcut requirements.
 *
 * @see specs/006-user-interface.md Section 6.9.2
 */

import { describe, it, expect, vi, beforeEach } from 'bun:test';
import { handleCanvasKeyDown, type KeyboardHandlerCallbacks } from './keyboard-handler';

/**
 * Create a mock keyboard event without DOM dependencies
 */
function createKeyEvent(
  key: string,
  options: Partial<{
    shiftKey: boolean;
    ctrlKey: boolean;
    metaKey: boolean;
    altKey: boolean;
    targetTagName: string;
    isContentEditable: boolean;
    targetClassList: string[];
  }> = {}
): KeyboardEvent {
  // Create a minimal target mock
  const target = {
    tagName: options.targetTagName ?? 'DIV',
    isContentEditable: options.isContentEditable ?? false,
    classList: {
      contains: (className: string) =>
        (options.targetClassList ?? []).includes(className),
    },
  };

  // Create mock event object
  const event = {
    key,
    shiftKey: options.shiftKey ?? false,
    ctrlKey: options.ctrlKey ?? false,
    metaKey: options.metaKey ?? false,
    altKey: options.altKey ?? false,
    target,
    preventDefault: vi.fn(),
    stopPropagation: vi.fn(),
  } as unknown as KeyboardEvent;

  return event;
}

/**
 * Create mock callbacks with all methods stubbed
 */
function createMockCallbacks(): KeyboardHandlerCallbacks & {
  mocks: {
    [K in keyof KeyboardHandlerCallbacks]: ReturnType<typeof vi.fn>;
  };
} {
  const mocks = {
    onPan: vi.fn(),
    onGoToToday: vi.fn(),
    onZoomIn: vi.fn(),
    onZoomOut: vi.fn(),
    onSetZoomLevel: vi.fn(),
    onClearSelection: vi.fn(),
    onToggleSelection: vi.fn(),
    onActivateSelected: vi.fn(),
    onToggleLock: vi.fn(),
    onDeleteSelected: vi.fn(),
    onShowKeyboardHelp: vi.fn(),
    onCloseDialog: vi.fn(),
    isShortcutsEnabled: vi.fn(() => true),
    hasOpenDialog: vi.fn(() => false),
    isDragging: vi.fn(() => false),
    getSelectedPmId: vi.fn(() => null),
  };

  return {
    ...mocks,
    mocks,
  };
}

describe('handleCanvasKeyDown', () => {
  let callbacks: ReturnType<typeof createMockCallbacks>;

  beforeEach(() => {
    callbacks = createMockCallbacks();
  });

  describe('Navigation Shortcuts', () => {
    it('handles ArrowUp to pan up', () => {
      const event = createKeyEvent('ArrowUp');
      const handled = handleCanvasKeyDown(event, callbacks);

      expect(handled).toBe(true);
      expect(callbacks.mocks.onPan).toHaveBeenCalledWith('up', 50);
    });

    it('handles ArrowDown to pan down', () => {
      const event = createKeyEvent('ArrowDown');
      const handled = handleCanvasKeyDown(event, callbacks);

      expect(handled).toBe(true);
      expect(callbacks.mocks.onPan).toHaveBeenCalledWith('down', 50);
    });

    it('handles ArrowLeft to pan left', () => {
      const event = createKeyEvent('ArrowLeft');
      const handled = handleCanvasKeyDown(event, callbacks);

      expect(handled).toBe(true);
      expect(callbacks.mocks.onPan).toHaveBeenCalledWith('left', 50);
    });

    it('handles ArrowRight to pan right', () => {
      const event = createKeyEvent('ArrowRight');
      const handled = handleCanvasKeyDown(event, callbacks);

      expect(handled).toBe(true);
      expect(callbacks.mocks.onPan).toHaveBeenCalledWith('right', 50);
    });

    it('handles Shift+Arrow for fast pan (3x amount)', () => {
      const event = createKeyEvent('ArrowUp', { shiftKey: true });
      const handled = handleCanvasKeyDown(event, callbacks);

      expect(handled).toBe(true);
      expect(callbacks.mocks.onPan).toHaveBeenCalledWith('up', 150);
    });

    it('handles Home key to go to today', () => {
      const event = createKeyEvent('Home');
      const handled = handleCanvasKeyDown(event, callbacks);

      expect(handled).toBe(true);
      expect(callbacks.mocks.onGoToToday).toHaveBeenCalled();
    });

    it('handles t key to go to today', () => {
      const event = createKeyEvent('t');
      const handled = handleCanvasKeyDown(event, callbacks);

      expect(handled).toBe(true);
      expect(callbacks.mocks.onGoToToday).toHaveBeenCalled();
    });

