   162→    case 'LOW_STOCK':
   163→      return 'warning-sign';
   164→    case 'UNAVAILABLE':
   165→      return 'error';
   166→    case 'ARRIVING':
   167→      return 'time';
   168→    default:
   169→      return 'help';
   170→  }
